doc.on("data", (c) => chunks.push(c));
var done = new Promise((resolve) => doc.on("end", resolve));
import_svg_to_pdfkit.default(doc, svg, 0, 0, { assumePt: true, width: W, height: H, DOMParser: $DOMParser });
doc.end();
await done;
var pdf = Buffer.concat(chunks);
if (outPath)
  await Bun.write(outPath, pdf);
else
  process.stdout.write(pdf);
